export type CustomerStatus = 'Ativo' | 'Suspenso';

export interface Customer {
  id: string;
  name: string;
  email: string;
  plan: string;
  status: CustomerStatus;
}

let customersDb: Customer[] = [
  { id: '1', name: 'Ana Paula Nunes', email: 'ana.nunes@provedor.com', plan: '400 Mega', status: 'Ativo' },
  { id: '2', name: 'Bruno Oliveira', email: 'bruno.oliveira@provedor.com', plan: '600 Mega', status: 'Ativo' },
  { id: '3', name: 'Carla Mendes', email: 'carla.mendes@provedor.com', plan: '200 Mega', status: 'Suspenso' },
  { id: '4', name: 'Diego Santos', email: 'diego.santos@provedor.com', plan: '1 Giga', status: 'Ativo' },
  { id: '5', name: 'Erika Lima', email: 'erika.lima@provedor.com', plan: '400 Mega', status: 'Ativo' },
  { id: '6', name: 'Felipe Costa', email: 'felipe.costa@provedor.com', plan: '600 Mega', status: 'Suspenso' },
];

export const fetchCustomers = async (): Promise<Customer[]> => {
  return new Promise((resolve) => {
    setTimeout(() => resolve([...customersDb]), 250);
  });
};
